// Ink 基本用法看起来和 React 没两样
import { render, Text, Box } from 'ink'

function App() {
  return (
    <Box flexDirection="column">
      <Text color="blue">欢迎使用 Claude Code</Text>
      <Text>按 q 键退出</Text>
    </Box>
  )
}

render(<App />)

// 屏幕路由的栈实现模式
class ScreenRouter {
  private stack: Array<ReactNode> = []

  push(screen: ReactNode) {
    this.stack.push(screen)
    this.render()
  }

  pop() {
    if (this.stack.length > 1) {
      this.stack.pop()
      this.render()
    }
  }

  private render() {
    const current = this.stack[this.stack.length - 1]
    inkRender(current)
  }
}

// 真色彩到ANSI转义序列的转换
function rgbToAnsi(r: number, g: number, b: number): string {
  // 检测终端是否支持真色彩
  if (supportsTrueColor(process.env.TERM)) {
    // 24位真色彩格式: \x1b[38;2;R;G;Bm
    return `\x1b[38;2;${r};${g};${b}m`
  }

  // 回退到256色模式
  const ansi256 = rgbToAnsi256(r, g, b)
  return `\x1b[38;5;${ansi256}m`
}

// 终端能力检测
function supportsTrueColor(term: string): boolean {
  return term?.includes('24bit') || 
         term?.includes('truecolor') ||
         process.env.COLORTERM === 'truecolor'
}
